// Formato esperado: '128/82 76 observação opcional'
// ou somente: '128/82'

const texto = $input.first().json.message?.text || '';

const matchPA = texto.match(/(\d{2,3})\s*\/\s*(\d{2,3})/);
if (!matchPA) {
  return [{ json: { erro: true, mensagem: 'Não consegui identificar a pressão. Envie no formato: sistólica/diastólica (ex: 128/82)' } }];
}

const sistolica = parseInt(matchPA[1]);
const diastolica = parseInt(matchPA[2]);

// BPM: número isolado após o padrão da pressão
const restante = texto.slice(matchPA.index + matchPA[0].length).trim();
const matchBpm = restante.match(/^(\d{2,3})/);
const bpm = matchBpm ? parseInt(matchBpm[1]) : null;
const observacao = matchBpm ? restante.slice(matchBpm[0].length).trim() : restante;

return [{
  json: {
    erro: false,
    sistolica,
    diastolica,
    bpm: bpm || undefined,
    observacao: observacao || undefined,
    origem: 'n8n',
    medido_em: new Date().toISOString().slice(0, 19),
    chat_id: $input.first().json.message?.chat?.id,
  }
}];
